import React from "react";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Dashboard() {
  return (
    <div className="container mt-5 text-center">
      <div className="card shadow-lg border-0 rounded-4 p-5">
        <h1 className="fw-bold mb-3 text-primary">¡Bienvenido al Sistema de Ventas! 🛍️</h1>
        <p className="fs-5 text-muted">
          Desde este panel podrás gestionar productos, categorías y mucho más.
        </p>
        <hr className="my-4" />
        <p className="text-secondary">
          Usa el menú superior para navegar entre las secciones disponibles.
        </p>
      </div>
    </div>
  );
}
